19→export function ListItem({
20→  index,
21→  icon,
22→  title,
23→  subtitle,
24→  accessories,
25→  onClick,
26→}: ListItemProps) {
27→  const { activeIndex, setActiveIndex } = useListContext();
28→  const isActive = activeIndex === index;
29→
30→  const handleMouseEnter = useCallback(() => {
31→    setActiveIndex(index);
32→  }, [
33→    index,
34→    setActiveIndex,
35→  ]);
36→
37→  const handleClick = useCallback(() => {
38→    onClick?.();
39→  }, [onClick]);
40→
41→  return (
42→    <div
43→      className={`list-item${isActive ? ' list-item--active' : ''}`}
44→      data-list-index={index}
45→      role="option"
46→      aria-selected={isActive}
47→      onMouseEnter={handleMouseEnter}
48→      onClick={handleClick}
49→    >
50→      <div className="list-item__left">
51→        {icon && <span className="list-item__icon">{icon}</span>}
52→        <span className="list-item__title">{title}</span>
