57→          {accessories.map((accessory, i) => (
58→            <span key={i} className="list-item__accessory">
59→              {accessory.icon}
60→              {accessory.text && (
61→                <span className="list-item__accessory-text">
62→                  {accessory.text}
63→                </span>
64→              )}
65→            </span>
66→          ))}
67→        </div>
68→      )}
69→    </div>
70→  );
