 1→import {
 2→  type ReactNode,
 3→  useCallback,
 4→  useEffect,
 5→  useMemo,
 6→  useRef,
 7→  useState,
 8→} from 'react';
 9→import './list.scss';
10→import { ListContext } from './list_context';
11→
12→interface ListProps {
13→  children: ReactNode;
14→  itemCount: number;
15→  onActiveIndexChange?: (index: number) => void;
16→}
17→
18→export function List({ children, itemCount, onActiveIndexChange }: ListProps) {
19→  const [activeIndex, setActiveIndexRaw] = useState(0);
20→  const containerRef = useRef<HTMLDivElement>(null);
21→
22→  const setActiveIndex = useCallback(
23→    (index: number) => {
24→      setActiveIndexRaw(index);
25→      onActiveIndexChange?.(index);
26→    },
27→    [onActiveIndexChange],
28→  );
29→
30→  useEffect(() => {
31→    if (itemCount === 0) {
32→      setActiveIndex(0);
33→    } else if (activeIndex >= itemCount) {
34→      setActiveIndex(itemCount - 1);
35→    }
36→  }, [
37→    itemCount,
38→    activeIndex,
39→    setActiveIndex,
40→  ]);
41→
42→  useEffect(() => {
43→    const container = containerRef.current;
44→    if (!container) return;
45→
46→    const activeElement = container.querySelector<HTMLElement>(
47→      `[data-list-index="${activeIndex}"]`,
48→    );
49→    activeElement?.scrollIntoView({ block: 'nearest' });
50→  }, [activeIndex]);
51→
52→  useEffect(() => {
53→    function handleKeyDown(e: KeyboardEvent) {
54→      if (itemCount === 0) return;
55→      if (e.metaKey || e.ctrlKey || e.altKey) return;
56→
57→      if (e.key === 'ArrowDown') {
58→        e.preventDefault();
59→        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
60→      } else if (e.key === 'ArrowUp') {
61→        e.preventDefault();
62→        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
63→      }
64→    }
65→
66→    window.addEventListener('keydown', handleKeyDown);
67→    return () => window.removeEventListener('keydown', handleKeyDown);
68→  }, [
69→    activeIndex,
70→    itemCount,
71→    setActiveIndex,
72→  ]);
73→
74→  const contextValue = useMemo(
75→    () => ({
76→      activeIndex,
77→      setActiveIndex,
78→    }),
79→    [
80→      activeIndex,
81→      setActiveIndex,
82→    ],
83→  );
84→
85→  return (
86→    <ListContext value={contextValue}>
87→      <div ref={containerRef} className="list" role="listbox">
88→        {children}
89→      </div>
90→    </ListContext>
91→  );
92→}
